-- ── PodFetch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PodFetch is a free, open-source, self-hosted podcast download and management server, built in Rust with a React web interface, that lets users archive, search, and sync podcasts on their own infrastructure.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (independent open-source project maintained primarily by a single developer, SamTV12345, with community contributors)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PodFetch Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PodFetch review: self-hosted podcast downloading, GPodder sync, and full-text transcript search. See how it compares to other self-hosted podcast servers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PodFetch is a free and open-source, self-hosted podcast manager distributed under the Apache-2.0 license and maintained on GitHub by developer SamTV12345, with the codebase written primarily in Rust for the backend and React with TypeScript for the web frontend. Unlike hosted commercial services such as Podbean, PodFetch is not a podcast hosting or publishing platform for creators; it is a downloading and archiving server that listeners run on their own hardware (a home server, NAS, or VPS) to pull episodes from RSS feeds, store them locally, and stream or download them through a browser-based interface. It ships as a Docker image that is rebuilt automatically on every commit to the main branch, and supports both SQLite and PostgreSQL as backing databases, making it deployable via a simple docker-compose setup. Key differentiators include native GPodder API compatibility, which lets existing podcast apps sync subscriptions and playback position with a self-hosted PodFetch instance instead of a third-party cloud sync service; support for Podcasting 2.0 transcript tags with full-text search across everything spoken in an episode; and the ability to auto-generate missing transcripts by connecting to any OpenAI-compatible Whisper API. Cross-device sync lets a listener start an episode on one device and resume on another, similar to commercial podcast apps, but entirely under the user's own control and without a subscription fee. PodFetch targets self-hosting enthusiasts, privacy-conscious podcast listeners, and homelab users who already run Docker-based services and want to own their podcast archive and metadata rather than relying on Apple, Spotify, or Google for subscription management. It has no company, funding, or pricing structure since it is entirely community-maintained open-source software; its closest comparables are other self-hosted podcast tools such as gpodder-web, AntennaPod (for the mobile client side), and Podgrab, rather than commercial hosting platforms like Podbean or Libsyn, which serve creators rather than listeners.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '63b21fd2-9266-4e94-acfa-f6a9f0e85347';

