-- ── Podia ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Podia is an all-in-one platform for creators to sell online courses, memberships, digital downloads, and coaching, combining a website builder, email marketing, and community tools in one subscription.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$42/month (Mover plan, billed monthly; 30-day free trial available)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Roughly 24 to 35 employees (fully remote team)$q$, company_size),
  headquarters = COALESCE($q$New York, United States (fully remote company)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Podia Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Podia review covering course creation, memberships, coaching, and email tools, plus 2026 pricing and how it compares to Kajabi, Teachable, and Thinkific.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Podia is an all-in-one creator commerce platform founded in 2014 by Spencer Fry, a serial entrepreneur who previously co-founded Carbonmade and Uncover, and who continues to serve as CEO. The company is fully remote, with a lean team estimated between roughly 24 and 35 employees spread across multiple continents, and it built its reputation as an accessible, lower-cost alternative to more complex course platforms. Podia lets creators sell online courses, memberships, digital downloads, coaching sessions, and live or in-person events, all from a single account that also includes a website builder, blog, landing pages, built-in checkout, email marketing, and a community/spaces feature for hosting discussions among students or members. Its key differentiator versus competitors like Kajabi, Teachable, and Thinkific is consolidation: rather than requiring separate tools for email marketing, community, and checkout, Podia bundles them together, and unlike some rivals it does not charge per-student fees, only percentage-based transaction fees that vary by plan. Pricing runs on a subscription model with three current tiers, Mover, Shaker, and Earthquaker, priced roughly from $42 to $150 per month on monthly billing (with annual billing offering savings), scaling by email subscriber limits, number of products, video storage, community 'spaces,' and transaction fee percentage, with a 30-day free trial requiring no credit card. Every tier includes the full feature set, including community, courses, downloads, coaching, events, website, custom domain, 1,900+ integrations, and support for sales tax across roughly 230 countries and more than 20 currencies. Podia's target users are independent creators, coaches, and small businesses selling knowledge products who want to launch quickly without stitching together multiple SaaS subscriptions or hiring a developer. Named competitors include Kajabi, Teachable, Thinkific, and Podbean-adjacent creator platforms like Gumroad for simpler digital product sales, though Podia differentiates itself by combining course, membership, and community features that those tools often split across separate products or add-ons.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '11aeaa6f-ca3a-4980-80c9-07d68c56564a';

