-- ── Podlove ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Podlove is a free, open-source suite of WordPress plugins, including a publisher, web player, and subscribe button, that lets podcasters self-host and independently publish their shows.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (volunteer-run open-source community, not a company)$q$, company_size),
  headquarters = COALESCE($q$Germany (community-run project; no formal corporate headquarters)$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$]::text[],
  seo_title = COALESCE($q$Podlove Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Podlove review: the open-source WordPress plugin suite for self-hosted podcasting, including the Publisher, Web Player, and subscribe tools.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Podlove is an open-source podcast publishing toolkit built as a suite of WordPress plugins, started in 2012 by German developers who felt existing podcasting tools of the time were outdated and unwieldy. It has no traditional company structure or funding round; instead it is maintained by a small volunteer community and supported financially through Open Collective, with development happening openly on GitHub under an MIT license. The flagship component is the Podlove Publisher, which turns a self-hosted WordPress installation into a full podcast publishing system, generating standards-compliant, highly configurable RSS feeds with fine-grained control over client app behavior, chapter marks, contributor credits, and WebVTT transcript support that surfaces in podcast apps. It integrates with the companion Podlove Web Player, an HTML5 player supporting multiple audio formats (MP3, AAC, Vorbis, Opus) and video formats (H.264, WebM, Theora), and the Podcast Subscribe Button widget for easy multi-platform subscription links. Podlove's core differentiator is that it turns podcasting into a fully self-hosted, self-owned activity built on WordPress, the world's most widely used content management system, rather than routing creators through a third-party SaaS host like Podbean, Libsyn, or Buzzsprout; this appeals strongly to podcasters who want complete control over their media files, feed structure, and data, and who are already comfortable running WordPress. The project has a particularly strong following among German-language podcasts and technology/politics shows, with notable users including Lage der Nation, Logbuch:Netzpolitik, and NDR's Corona Virus Update. Because it is free and open source, Podlove has no pricing tiers or plans; its practical cost is the WordPress hosting, storage, and bandwidth a podcaster arranges separately. Its target users are technically comfortable independent podcasters, public broadcasters, and organizations that prioritize data ownership and open standards over the convenience of a managed hosting dashboard, distinguishing it from both commercial hosts and other self-hosted tools such as Castopod.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b01d76ea-bf87-434f-abc4-af2bc181bdcc';

