-- ── Polis ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Polis is an open-source, AI-assisted platform for large-scale public deliberation that lets participants submit and vote on statements, then uses machine learning to surface areas of consensus and disagreement among large groups.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small nonprofit team)$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Multiple additional languages supported for participant-facing conversations$q$]::text[],
  seo_title = COALESCE($q$Polis Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Polis (pol.is) review: open-source AI-assisted civic deliberation platform used by governments worldwide to map public opinion at scale.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Polis, accessible at pol.is, is an open-source platform for large-scale public deliberation and opinion mapping, originally built around 2012 by Colin Megill, Christopher Small, and Michael Bjorkegren in Seattle, in response to communication challenges observed during the 2009-2010 Iranian Green Revolution and the 2011 Occupy Wall Street protests. The technology was open-sourced under the AGPLv3 license in 2016, following a request from the Taiwanese government, which became one of Polis's most prominent adopters through its vTaiwan and Join platforms. In 2018, the creators formalized ongoing stewardship of the project as The Computational Democracy Project, a 501(c)3 nonprofit headquartered in Seattle, which continues to design, engineer, and maintain Polis and provide support to journalists, academic researchers, and public servants. Unlike traditional online surveys or comment sections, Polis lets participants submit short text statements about a topic, which other participants then vote to agree, disagree, or pass on; rather than free-text replies that create noise, this vote-based structure is fed into a real-time statistical and machine-learning pipeline that clusters participants by opinion pattern and surfaces both consensus statements (which most groups agree on) and divisive statements, visualized as an interactive opinion map. Its core differentiator from conventional survey tools or social media polling is that its algorithms are explicitly designed to find agreement and understand nuance rather than to maximize engagement or virality, making it a tool for sensemaking rather than debate. Polis is entirely free and open source, with no subscription tiers, and has been used by governments and civic organizations in the United States, Canada, Singapore, the Philippines, Finland, Spain, and Taiwan, as well as by journalists and researchers for public opinion projects covered by outlets including The New York Times, The Guardian, The Economist, and MIT Technology Review. Its target users are governments, civic technologists, researchers, and organizations running large-scale public consultations or citizens' assemblies. Comparable or adjacent tools include Loomio and Decidim for participatory democracy, and Remesh, a commercial AI-assisted public engagement platform, though Polis differentiates itself through its open-source AGPLv3 license, nonprofit governance, and specific statement-voting-plus-clustering methodology.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3dea5eed-dd33-4128-91b3-fee23cd6f46a';

