  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Swedish$q$, $q$German$q$, $q$Dutch$q$, $q$Finnish$q$, $q$French$q$, $q$Hungarian$q$, $q$Slovenian$q$, $q$Luxembourgish$q$]::text[],
  seo_title = COALESCE($q$POMjs Review 2026: Features, Privacy and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$POMjs review: a free, open-source, no-tracking random password generator built in plain JavaScript, with multi-language support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$POMjs is a small, free, open-source random password generator built entirely in HTML and plain JavaScript by Swedish developer Joaquim Homrighausen, first released around October 2022 (copyright notices cite 2022 and 2023). It is hosted at password.oppetmoln.se and its source code is published on GitHub under the GPLv2 license, where users can review, modify, or self-host the tool. POMjs has no company behind it, no funding, and no commercial pricing; it is a personal open-source utility rather than a startup or SaaS product. Its defining characteristics, and the reason it stands apart from most password-generator websites and browser extensions, are its explicit privacy stance and minimalism: the tool loads no external resources, sets no cookies, and includes no analytics or tracking code of any kind, generating passwords entirely client-side in the browser. It automatically detects and supports dark mode, and its interface has been translated into roughly nine languages, including Swedish, German, Dutch, Finnish, French, Hungarian, Slovenian, and Luxembourgish, in addition to English, reflecting its European, and particularly Nordic, origin and audience. The creator describes the goal as building something small, useful, and reasonably free of dependencies, rather than a feature-rich commercial product; as such it lacks the browser-extension integration, password manager syncing, breach-checking, or team/enterprise features found in commercial tools like 1Password, Bitwarden, or LastPass password generators. Its target users are privacy-conscious individuals who want a quick, trustworthy, no-signup password generator without handing data to a third party, developers who want to inspect or self-host a transparent, auditable generator, and non-English speakers who prefer a localized interface. Because it is not a company or platform with a roadmap, growth metrics, or business model, comparisons should be made narrowly to other free client-side password-generator tools and open-source utilities rather than to full password-management suites; relevant comparables include Bitwarden's free online password generator and other lightweight open-source generators available on GitHub, rather than directory-scale SaaS competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd83a1349-8ab9-4eea-8c4f-73b628234bab';

