-- ── Port ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Port is an internal developer portal and platform engineering tool that lets organizations build a software catalog, automate infrastructure actions, and enforce governance through scorecards and self-service workflows.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $30/seat/month)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Port Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Port (getport.io) review covering its internal developer portal, software catalog, self-service actions, 2026 pricing, and top platform engineering alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Port, marketed at getport.io, is an internal developer portal (IDP) and platform engineering tool founded in 2022 by Zohar Einy and Yonatan Boguslavski, who drew on their experience building an internal developer portal used by more than 2,000 developers inside Israel's Unit 8200 intelligence corps. The company is headquartered in Tel Aviv, Israel, has raised a total of roughly $160 million across multiple funding rounds including an $18 million raise in 2023 and a later $35 million round, and employs an estimated 51 to 200 people as of 2026. Port's core product lets platform engineering and DevOps teams build a centralized software catalog (which Port calls a 'Context Lake') that models services, infrastructure, and ownership data, then layers on self-service actions, workflow orchestration, scorecards for measuring service health and compliance, and an interface designer for building custom internal developer experiences, all aimed at reducing the cognitive load developers face navigating microservices, cloud infrastructure, and CI/CD pipelines. Its key differentiator versus building an internal portal from scratch with tools like Backstage (the open-source project originated by Spotify) is that Port is a fully managed SaaS product requiring no dedicated platform team to build and maintain a custom Backstage instance, while still offering deep customization through its catalog data model and action automations; it also increasingly markets AI agent capabilities layered on top of its catalog data. Pricing follows a freemium, per-seat model: a free tier supports up to 15 seats with 10,000 catalog entities and 500 automation runs, a Basic tier starts at $30 per seat per month, a Standard tier for growing engineering organizations (up to 200 developers) starts at $40 per seat per month with added governance and single sign-on, and an Enterprise tier offers custom platform-fee-plus-per-seat pricing with unlimited scale, dedicated support SLAs, and advanced security controls like SCIM and IP allowlisting. Port's target users are platform engineering teams, DevOps engineers, and site reliability engineers at mid-size to large engineering organizations seeking to standardize service ownership, reduce onboarding friction, and enforce governance without building custom tooling. Named competitors include Backstage (self-hosted, open source), Cortex, OpsLevel, and Atlassian Compass, all of which compete in the internal developer portal and platform engineering category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0db14796-fc34-4c7e-aed4-8d302ce97b7d';

